use std::collections::HashMap;

struct DataLoaderHandler {
    cache: HashMap<String, String>,
}

impl DataLoaderHandler {
    fn new() -> Self {
        DataLoaderHandler { cache: HashMap::new() }
    }

    fn load_batch(&mut self, keys: &[String]) -> Vec<Option<String>> {
        let mut results = Vec::with_capacity(keys.len());
        for key in keys.iter() {
            if let Some(value) = self.cache.get(key) {
                results.push(Some(value.clone()));
            } else {
                results.push(None);
            }
        }
        results
    }

    fn process_ids(&mut self, ids: &[String]) -> Vec<Option<String>> {
        let batch = ids.to_vec();
        self.load_batch(&batch)
    }
}

fn main() {
    let mut handler = DataLoaderHandler::new();
    handler.cache.insert("user:1".to_string(), "Data for user 1".to_string());
    handler.cache.insert("product:A".to_string(), "Data for product A".to_string());

    let ids_to_load = vec!["user:1".to_string(), "user:2".to_string(), "product:A".to_string()];

    let results = handler.process_ids(&ids_to_load);

    for (i, result) in results.iter().enumerate() {
        if let Some(data) = result { 
            println!("Successfully loaded item {}: {}", i + 1, data);
        } else {
            println!("Failed to load item {}: Unknown ID.", i + 1);
        }
    }
}

use std::sync::{Arc, Mutex};

struct EventSystem {
    listeners: Mutex<Vec<Box<dyn Fn(&str) + Send>>>,
}

impl EventSystem {
    fn new() -> Self {
        EventSystem { listeners: Mutex::new(Vec::new()) }
    }

    fn subscribe<F>(&self, callback: F) where F: Fn(&str) + 'static + Send + Sync {} 
    fn publish(&self, event_data: &str) {
        let mut listeners = self.listeners.lock().unwrap();
        for listener in listeners.iter() {
            listener(event_data);
        }
    }

    fn add_listener<F>(&self, callback: F) where F: Fn(&str) + 'static + Send + Sync {
        let mut listeners = self.listeners.lock().unwrap();
        listeners.push(Box::new(callback));
    }
}

fn main() {
    let event_system = Arc::new(EventSystem::new());

    event_system.add_listener(|data| { 
        println!("Logger received event for: {}", data);
    });

    event_system.add_listener(|data| { 
        println!("FileProcessor noticed change on: {}", data);
    });

    let system_clone = Arc::clone(&event_system);
    std::thread::spawn(move || {
        std::thread::sleep(std::time::Duration::from_millis(50));
        system_clone.publish("ImageBatchComplete");
    });

    std::thread::sleep(std::time::Duration::from_millis(100));
}

use std::collections::HashMap;
use std::sync::{Arc, Mutex};

struct BuildEventSystem {
    subscribers: Mutex<HashMap<String, Vec<Box<dyn Fn(&str) + Send + Sync>>>>,
}

impl BuildEventSystem {
    fn new() -> Self {
        BuildEventSystem { 
            subscribers: Mutex::new(HashMap::new()),
        }
    }

    fn subscribe<F>(&self, event_type: &str, callback: F) -> Result<(), &'static str>
    where
        F: Fn(&str) + Send + Sync + 'static,
    {
        let mut subs = self.subscribers.lock().unwrap();
        subs.entry(event_type.to_string()).or_default().push(Box::new(move |data| {
            // To satisfy the generic constraints and deal with captured data if any, 
            // we use a specific closure form that is generally accepted for callbacks.
            // Since the original code didn't capture anything complex, just boxing the provided Fn should work if F: 'static.
            // The issue was related to how Rust inferred lifetimes when using Box::new on closures directly in some contexts.
            // We explicitly move into the box closure.
            let _ = callback(data);
        }));
        Ok(())
    }

    fn publish(&self, event_type: &str, data: &str) {
        let subs = self.subscribers.lock().unwrap();
        if let Some(callbacks) = subs.get(event_type) {
            for callback in callbacks.iter() {
                callback(data);
            }
        }
    }
}

fn main() {
    let event_system = Arc::new(BuildEventSystem::new());

    event_system.subscribe("file_updated", |data| {
