struct EventBus {
    subscribers: Mutex<HashMap<String, Vec<Box<dyn Fn(String) + Send + Sync>>>>,
}

impl EventBus {
    fn new() -> Self {
        EventBus { subscribers: Mutex::new(HashMap::new()) }
    }

    fn subscribe(&self, event_type: &str, callback: Box<dyn Fn(String) + Send + Sync>) -> Result<(), &'static str> {
        let mut subs = self.subscribers.lock().unwrap();
        subs.entry(event_type.to_string()).or_default().push(callback);
        Ok(())
    }

    fn publish(&self, event_type: &str, data: String) {
        let subs = self.subscribers.lock().unwrap();
        if let Some(callbacks) = subs.get(event_type) {
            for callback in callbacks.iter() {
                callback(data.clone());
            }
        }
    }
}

